import React, { useEffect, useState } from "react";
import axios from "axios";
import Layout from "../components/Layout";

const LabourDashboard = () => {
  const [jobs, setJobs] = useState([]);
  const [myJobs, setMyJobs] = useState([]);

  const user = JSON.parse(localStorage.getItem("user"));
  const token = localStorage.getItem("token");

  useEffect(() => {
    fetchJobs();
    fetchMyJobs();
  }, []);

  // GET ALL OPEN JOBS
  const fetchJobs = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/jobs/all", {
        headers: {
          Authorization: `Bearer ${token}`
        }
      });

      setJobs(res.data);
    } catch (err) {
      console.log("Error loading jobs");
    }
  };

  // GET MY JOBS
  const fetchMyJobs = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/jobs/my-jobs/${user.email}`,
        {
          headers: {
            Authorization: `Bearer ${token}`
          }
        }
      );

      setMyJobs(res.data);
    } catch (err) {
      console.log("Error loading my jobs");
    }
  };

  // ACCEPT JOB
  const acceptJob = async (id) => {
    try {
      await axios.put(
        `http://localhost:5000/api/jobs/accept/${id}`,
        {},
        {
          headers: {
            Authorization: `Bearer ${token}`
          }
        }
      );

      fetchJobs();
      fetchMyJobs();
    } catch (err) {
      console.log("Error accepting job");
    }
  };

  // COMPLETE JOB
  const completeJob = async (id) => {
    try {
      await axios.put(
        `http://localhost:5000/api/jobs/complete/${id}`,
        {},
        {
          headers: {
            Authorization: `Bearer ${token}`
          }
        }
      );

      fetchMyJobs();
    } catch (err) {
      console.log("Error completing job");
    }
  };

  return (
    <Layout title="Labour Dashboard">

      {/* AVAILABLE JOBS */}
      <h3>Available Jobs</h3>

      {jobs.length === 0 && <p>No jobs available</p>}

      {jobs.map((job) => (
        <div key={job._id} style={styles.card}>
          <h3>{job.title}</h3>
          <p>{job.description}</p>
          <p>📍 {job.location}</p>
          <p>💰 {job.price}</p>

          <button
            onClick={() => acceptJob(job._id)}
            style={styles.acceptBtn}
          >
            Accept Job
          </button>
        </div>
      ))}

      {/* MY JOBS */}
      <h3 style={{ marginTop: "30px" }}>My Jobs</h3>

      {myJobs.length === 0 && <p>No assigned jobs</p>}

      {myJobs.map((job) => (
        <div key={job._id} style={styles.card}>
          <h3>{job.title}</h3>
          <p>📍 {job.location}</p>

          <p>
            Status:{" "}
            <span
              style={{
                color:
                  job.status === "completed"
                    ? "green"
                    : job.status === "accepted"
                    ? "blue"
                    : "orange"
              }}
            >
              {job.status}
            </span>
          </p>

          {job.status === "accepted" && (
            <button
              onClick={() => completeJob(job._id)}
              style={styles.completeBtn}
            >
              Mark as Completed
            </button>
          )}

          {job.status === "completed" && (
            <p style={{ color: "green", fontWeight: "bold" }}>
              ✔ Completed
            </p>
          )}
        </div>
      ))}

    </Layout>
  );
};

export default LabourDashboard;

/* ---------------- STYLES ---------------- */

const styles = {
  card: {
    background: "white",
    padding: "15px",
    marginBottom: "15px",
    borderRadius: "12px",
    boxShadow: "0 2px 10px rgba(0,0,0,0.08)"
  },

  acceptBtn: {
    background: "#16a34a",
    color: "white",
    border: "none",
    padding: "8px 12px",
    marginTop: "10px",
    borderRadius: "6px",
    cursor: "pointer"
  },

  completeBtn: {
    background: "#2563eb",
    color: "white",
    border: "none",
    padding: "8px 12px",
    marginTop: "10px",
    borderRadius: "6px",
    cursor: "pointer"
  }
};
